import { describe, expect, it } from 'vitest';
import {
  insertWormhole,
  wormholeTransitiveReach,
} from './wormhole-topology';
import type { WormholeConnection } from './wormhole-topology';
import { createCausalTopology } from './causal-topology';
import type { SpacetimeEvent } from './causal-topology';
import { LIGHT_PICOLORENZO_LY } from './math';

// ─── Test Fixtures ──────────────────────────────────────────────────

const NOW = 1000; // pLo

/** Earth: origin, now. */
const earth: SpacetimeEvent = {
  id: 'earth',
  label: 'Earth',
  x: 0,
  y: 0,
  z: 0,
  pLo: NOW,
};

/** Proxima Centauri: 4.24 ly away, same time as Earth. */
const proxima: SpacetimeEvent = {
  id: 'proxima',
  label: 'Proxima',
  x: 4.24,
  y: 0,
  z: 0,
  pLo: NOW,
};

/** Sirius: 8.6 ly away, same time as Earth. */
const sirius: SpacetimeEvent = {
  id: 'sirius',
  label: 'Sirius',
  x: 8.6,
  y: 0,
  z: 0,
  pLo: NOW,
};

/** Future Earth: same position as Earth, 1000 pLo later. */
const futureEarth: SpacetimeEvent = {
  id: 'future-earth',
  label: 'Future Earth',
  x: 0,
  y: 0,
  z: 0,
  pLo: NOW + 1000,
};

// ─── insertWormhole ─────────────────────────────────────────────────

describe('insertWormhole', () => {
  it('connects two simultaneous spacelike-separated events and produces rewired edges', () => {
    const topology = createCausalTopology([earth, proxima, sirius]);
    const wormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'proxima',
      traversalTimePLo: 0,
      label: 'Earth-Proxima Bridge',
    };

    const result = insertWormhole(topology, wormhole);

    // The earth-proxima pair should be rewired from VENT to PROCESS
    expect(result.rewiredEdges.length).toBeGreaterThanOrEqual(1);
    const earthProximaRewire = result.rewiredEdges.find(
      (e) =>
        (e.sourceId === 'earth' && e.targetId === 'proxima') ||
        (e.sourceId === 'proxima' && e.targetId === 'earth')
    );
    expect(earthProximaRewire).toBeDefined();
    expect(earthProximaRewire!.originalEdgeType).toBe('VENT');
    expect(earthProximaRewire!.newEdgeType).toBe('PROCESS');
  });

  it('marks source as GnosisWormholeTopology', () => {
    const topology = createCausalTopology([earth, proxima]);
    const wormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'proxima',
      traversalTimePLo: 0,
    };

    const result = insertWormhole(topology, wormhole);
    expect(result.source).toBe('GnosisWormholeTopology');
  });

  it('preserves the same event count in original and modified topologies', () => {
    const topology = createCausalTopology([earth, proxima, sirius, futureEarth]);
    const wormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'sirius',
      traversalTimePLo: 0,
    };

    const result = insertWormhole(topology, wormhole);
    expect(result.modifiedTopology.events.length).toBe(
      result.originalTopology.events.length
    );
  });

  it('produces same or fewer spacelike edges in the modified topology', () => {
    const topology = createCausalTopology([earth, proxima, sirius]);
    const wormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'proxima',
      traversalTimePLo: 0,
    };

    const result = insertWormhole(topology, wormhole);
    expect(result.modifiedTopology.spacelikeEdges.length).toBeLessThanOrEqual(
      result.originalTopology.spacelikeEdges.length
    );
  });

  it('has non-negative connectivity gain', () => {
    const topology = createCausalTopology([earth, proxima, sirius]);
    const wormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'proxima',
      traversalTimePLo: 0,
    };

    const result = insertWormhole(topology, wormhole);
    expect(result.connectivityGain).toBeGreaterThanOrEqual(0);
  });

  it('creates new causal pairs between co-temporal spacelike-separated events', () => {
    const topology = createCausalTopology([earth, proxima, sirius]);
    const wormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'proxima',
      traversalTimePLo: 0,
    };

    const result = insertWormhole(topology, wormhole);

    // At minimum the earth-proxima pair should be newly causal
    expect(result.newlyCausalPairs.length).toBeGreaterThanOrEqual(1);
    const hasEarthProxima = result.newlyCausalPairs.some(
      (p) =>
        (p.eventA === 'earth' && p.eventB === 'proxima') ||
        (p.eventA === 'proxima' && p.eventB === 'earth')
    );
    expect(hasEarthProxima).toBe(true);
  });

  it('lists only pairs that were VENT and became PROCESS in newlyCausalPairs', () => {
    const topology = createCausalTopology([earth, proxima, futureEarth]);
    const wormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'proxima',
      traversalTimePLo: 0,
    };

    const result = insertWormhole(topology, wormhole);

    // Every newly causal pair must correspond to an original VENT edge
    for (const pair of result.newlyCausalPairs) {
      const originalEdge = topology.edges.find(
        (e) =>
          (e.sourceId === pair.eventA && e.targetId === pair.eventB) ||
          (e.sourceId === pair.eventB && e.targetId === pair.eventA)
      );
      expect(originalEdge).toBeDefined();
      expect(originalEdge!.edgeType).toBe('VENT');
    }
  });

  it('zero traversal time wormhole has maximum connectivity gain', () => {
    const topology = createCausalTopology([earth, proxima, sirius]);

    const instant: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'proxima',
      traversalTimePLo: 0,
    };
    const slow: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'proxima',
      traversalTimePLo: 1e12,
    };

    const instantResult = insertWormhole(topology, instant);
    const slowResult = insertWormhole(topology, slow);

    expect(instantResult.connectivityGain).toBeGreaterThanOrEqual(
      slowResult.connectivityGain
    );
  });

  it('wormhole between already causally connected events does not change connectivity', () => {
    // futureEarth is in Earth's future light cone (same position, later time)
    // so they are already timelike-connected
    const topology = createCausalTopology([earth, futureEarth]);
    const wormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'future-earth',
      traversalTimePLo: 0,
    };

    const result = insertWormhole(topology, wormhole);

    // No spacelike edges to rewire -- both events are already causally linked
    expect(result.rewiredEdges.length).toBe(0);
    expect(result.newlyCausalPairs.length).toBe(0);
    expect(result.connectivityGain).toBe(0);
  });

  it('throws when a wormhole mouth event does not exist', () => {
    const topology = createCausalTopology([earth, proxima]);
    const wormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'nonexistent',
      traversalTimePLo: 0,
    };

    expect(() => insertWormhole(topology, wormhole)).toThrow(
      'Wormhole mouth B event not found'
    );
  });
});

// ─── wormholeTransitiveReach ────────────────────────────────────────

describe('wormholeTransitiveReach', () => {
  it('from earth through earth-proxima wormhole, proxima becomes reachable', () => {
    const topology = createCausalTopology([earth, proxima, sirius]);
    const wormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'proxima',
      traversalTimePLo: 0,
    };

    const newlyReachable = wormholeTransitiveReach(topology, wormhole, 'earth');

    expect(newlyReachable).toContain('proxima');
  });

  it('returns empty array when no new events become reachable', () => {
    // earth and futureEarth are already causally connected
    const topology = createCausalTopology([earth, futureEarth]);
    const wormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'future-earth',
      traversalTimePLo: 0,
    };

    const newlyReachable = wormholeTransitiveReach(topology, wormhole, 'earth');

    // futureEarth is already reachable from earth via timelike edge,
    // so the wormhole adds nothing
    expect(newlyReachable.length).toBe(0);
  });

  it('wormhole with large traversalTimePLo still reports transitive reach', () => {
    const topology = createCausalTopology([earth, proxima, sirius]);
    const instantWormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'proxima',
      traversalTimePLo: 0,
    };
    const slowWormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'proxima',
      traversalTimePLo: 1e12,
    };

    const instantReach = wormholeTransitiveReach(
      topology,
      instantWormhole,
      'earth'
    );
    const slowReach = wormholeTransitiveReach(topology, slowWormhole, 'earth');

    // Both should include proxima (the wormhole connection itself
    // provides reachability regardless of traversal time in the
    // transitive reach model -- the topology edges determine
    // structure, traversal time affects physical plausibility)
    expect(instantReach).toContain('proxima');
    expect(slowReach).toContain('proxima');

    // Instant wormhole should reach at least as many events
    expect(instantReach.length).toBeGreaterThanOrEqual(slowReach.length);
  });

  it('chained reach: earth → proxima wormhole → near-proxima if proxima has causal future', () => {
    // Earth and proxima are spacelike at the same time.
    // nearProxima is very close to proxima (0.001 ly away) but slightly later,
    // so proxima→nearProxima is timelike. But earth→nearProxima is spacelike
    // because the spatial distance (4.241 ly) vastly exceeds the tiny time gap.
    const earlyProxima: SpacetimeEvent = {
      id: 'proxima',
      label: 'Proxima',
      x: 4.24,
      y: 0,
      z: 0,
      pLo: NOW,
    };
    const nearProxima: SpacetimeEvent = {
      id: 'near-proxima',
      label: 'Near Proxima',
      x: 4.241,
      y: 0,
      z: 0,
      // Needs enough time for light to cross 0.001 ly:
      // 0.001 / LIGHT_PICOLORENZO_LY ≈ 0.1165 pLo, so 1 pLo is plenty
      // But NOT enough for light to cross 4.241 ly from earth:
      // 4.241 / LIGHT_PICOLORENZO_LY ≈ 494 pLo, so 1 pLo is far too little
      pLo: NOW + 1,
    };
    const topology = createCausalTopology([earth, earlyProxima, nearProxima]);
    const wormhole: WormholeConnection = {
      mouthA: 'earth',
      mouthB: 'proxima',
      traversalTimePLo: 0,
    };

    const newlyReachable = wormholeTransitiveReach(topology, wormhole, 'earth');

    // Through the wormhole earth→proxima, then proxima→nearProxima causally
    expect(newlyReachable).toContain('proxima');
    expect(newlyReachable).toContain('near-proxima');
  });
});
